INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'A2', 'listening', 'At the Doctor', 'A dialogue during a clinic visit.', '{"type":"listen_and_choose","instructions":"Listen and answer based on the conversation.","exercises":[{"prompt":"Good morning. I feel very weak and have a slight fever.","question":"How does the patient feel?","options":["Strong","Weak","Hungry"],"correct":1,"hint":"Listen for ''weak''."},{"prompt":"Let me check your temperature. It is 38.5 degrees.","question":"What is the temperature?","options":["36.5","37.5","38.5"],"correct":2,"hint":"Number check."},{"prompt":"I also have a sore throat since yesterday evening.","question":"When did the sore throat start?","options":["Yesterday morning","Yesterday evening","This morning"],"correct":1,"hint":"Timing words."},{"prompt":"Take this medicine twice a day after meals.","question":"How often should they take medicine?","options":["Once a day","Twice a day","Every hour"],"correct":1,"hint":"Twice means two times."},{"prompt":"Avoid cold drinks and get plenty of rest this weekend.","question":"What should they avoid?","options":["Rest","Cold drinks","Medicine"],"correct":1,"hint":"Listen for the negative."}]}', 11),
('en', 'A2', 'listening', 'Grocery Shopping List', 'Identifying specific items from a list.', '{"type":"listen_and_choose","instructions":"Which item is needed?","exercises":[{"prompt":"We are out of butter, so buy two packs.","question":"What to buy?","options":["Milk","Butter","Cheese"],"correct":1,"hint":"Fatty dairy product."},{"prompt":"Get some sparkling water, not the still one.","question":"Which water?","options":["Still","Sparkling","Tap"],"correct":1,"hint":"Water with bubbles."},{"prompt":"Make sure the eggs are fresh and brown.","question":"What color eggs?","options":["White","Brown","Blue"],"correct":1,"hint":"Natural egg color."},{"prompt":"I need olive oil for the salad dressing.","question":"What kind of oil?","options":["Sunflower","Olive","Coconut"],"correct":1,"hint":"Mediterranean oil."},{"prompt":"Don''t forget to pick up some dark chocolate.","question":"Which chocolate type?","options":["Milk","White","Dark"],"correct":2,"hint":"Higher cocoa content."}]}', 12),
('en', 'A2', 'listening', 'The News Snippet', 'Identifying key information in a report.', '{"type":"listen_and_choose","instructions":"Find the key fact.","exercises":[{"prompt":"The city marathon will start at 7am tomorrow morning.","question":"What event is happening?","options":["Concert","Marathon","Fair"],"correct":1,"hint":"Running event."},{"prompt":"Heavy rain is expected in the northern areas.","question":"Where will it rain?","options":["South","East","North"],"correct":2,"hint":"Direction."},{"prompt":"A new library opened on Main Street yesterday.","question":"What building opened?","options":["School","Library","Gym"],"correct":1,"hint":"Book place."},{"prompt":"Public transport is free for students this week.","question":"Who gets free transport?","options":["Seniors","Students","Children"],"correct":1,"hint":"School goers."},{"prompt":"The local team won the game by two points.","question":"By how much did they win?","options":["1","2","3"],"correct":1,"hint":"Number hearing."}]}', 13),
('en', 'A2', 'listening', 'Ordering at a Restaurant', 'Complex meal choices.', '{"type":"listen_and_choose","instructions":"What is the order detail?","exercises":[{"prompt":"I would like the grilled salmon with steamed vegetables.","question":"What is the main course?","options":["Chicken","Salmon","Pasta"],"correct":1,"hint":"Fish."},{"prompt":"Could I have fries instead of salad?","question":"What does the customer prefer?","options":["Salad","Fries","Rice"],"correct":1,"hint":"Potato item."},{"prompt":"I am allergic to nuts, please check the ingredients.","question":"What is the allergy?","options":["Dairy","Nuts","Gluten"],"correct":1,"hint":"Nut warning."},{"prompt":"The table for four is ready in the garden.","question":"Where is the table?","options":["Inside","Balcony","Garden"],"correct":2,"hint":"Outdoor area."},{"prompt":"I''ll have a glass of red wine, please.","question":"What drink?","options":["Beer","Wine","Water"],"correct":1,"hint":"Grape drink."}]}', 14),
('en', 'A2', 'listening', 'Travel Announcements', 'Train and airport info.', '{"type":"listen_and_choose","instructions":"What info is given?","exercises":[{"prompt":"The train to London is delayed by fifteen minutes.","question":"How long is the delay?","options":["5 mins","10 mins","15 mins"],"correct":2,"hint":"Listen for 15."},{"prompt":"Please go to gate 42 for boarding.","question":"Which gate?","options":["24","42","52"],"correct":1,"hint":"Number reversal risk."},{"prompt":"Keep your bags with you at all times.","question":"What to keep?","options":["Bags","Phones","Tickets"],"correct":0,"hint":"Luggage."},{"prompt":"Platform three is closed for maintenance.","question":"Which platform is closed?","options":["2","3","4"],"correct":1,"hint":"Number."},{"prompt":"The next flight departs at six forty-five.","question":"Departure time?","options":["6:15","6:45","7:15"],"correct":1,"hint":"Quarter to seven."}]}', 15);
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'A2', 'speaking', 'Narrating the Past', 'Describe a yesterday event.', '{"type":"speak_and_repeat","instructions":"Narrate the sentence in past tense.","exercises":[{"prompt":"Yesterday, I went to the park with my dog.","expected":"Yesterday I went to the park with my dog","hint":"Past of go."},{"prompt":"I saw a very famous singer at the mall.","expected":"I saw a very famous singer at the mall","hint":"Past of see."},{"prompt":"We ate dinner at a small Italian restaurant.","expected":"We ate dinner at a small Italian restaurant","hint":"Past of eat."},{"prompt":"I finished my homework late last night.","expected":"I finished my homework late last night","hint":"Past of finish."},{"prompt":"It was a very beautiful and sunny day.","expected":"It was a very beautiful and sunny day","hint":"Past condition."}]}', 11),
('en', 'A2', 'speaking', 'Giving Reasons', 'Use ''because'' in speech.', '{"type":"speak_and_repeat","instructions":"Connect the reason clearly.","exercises":[{"prompt":"I am happy because I passed my exam.","expected":"I am happy because I passed my exam","hint":"Emotion plus reason."},{"prompt":"I stayed home because it was raining.","expected":"I stayed home because it was raining","hint":"Action plus reason."},{"prompt":"He is tired because he worked all night.","expected":"He is tired because he worked all night","hint":"Status plus reason."},{"prompt":"We went out because we were hungry.","expected":"We went out because we were hungry","hint":"Motivation."},{"prompt":"I like English because it is useful.","expected":"I like English because it is useful","hint":"Preference."}]}', 12),
('en', 'A2', 'speaking', 'Future Plans', 'Talk about upcoming events.', '{"type":"speak_and_repeat","instructions":"State your future plan.","exercises":[{"prompt":"I am going to visit my parents next week.","expected":"I am going to visit my parents next week","hint":"Going to future."},{"prompt":"We will travel to Japan in the summer.","expected":"We will travel to Japan in the summer","hint":"Will future."},{"prompt":"She is starting a new job tomorrow morning.","expected":"She is starting a new job tomorrow morning","hint":"Present continuous as future."},{"prompt":"I hope to buy a new car soon.","expected":"I hope to buy a new car soon","hint":"Aspiration."},{"prompt":"They are planning a big party for Saturday.","expected":"They are planning a big party for Saturday","hint":"Social plan."}]}', 13),
('en', 'A2', 'speaking', 'Asking for Advice', 'Requests for suggestions.', '{"type":"speak_and_repeat","instructions":"Ask for advice clearly.","exercises":[{"prompt":"What should I wear for the interview?","expected":"What should I wear for the interview","hint":"Using should."},{"prompt":"Where do you think is the best place to eat?","expected":"Where do you think is the best place to eat","hint":"Asking opinion."},{"prompt":"How can I improve my English speaking?","expected":"How can I improve my English speaking","hint":"Asking for help."},{"prompt":"Could you recommend a good movie to watch?","expected":"Could you recommend a good movie to watch","hint":"Requesting recommendation."},{"prompt":"Do you think I should buy this jacket?","expected":"Do you think I should buy this jacket","hint":"Check for opinion."}]}', 14),
('en', 'A2', 'speaking', 'Describing a Room', 'Use prepositions of place.', '{"type":"speak_and_repeat","instructions":"Describe the arrangement.","exercises":[{"prompt":"The lamp is on the table next to the bed.","expected":"The lamp is on the table next to the bed","hint":"On/Next to."},{"prompt":"There is a large rug under the coffee table.","expected":"There is a large rug under the coffee table","hint":"Under."},{"prompt":"The books are between the clock and the vase.","expected":"The books are between the clock and the vase","hint":"Between."},{"prompt":"My keys are inside the small blue box.","expected":"My keys are inside the small blue box","hint":"Inside."},{"prompt":"The picture is hanging above the sofa.","expected":"The picture is hanging above the sofa","hint":"Above."}]}', 15);
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'A2', 'reading', 'The Travel Blog', 'Read about a trip to the mountains.', '{"type":"read_and_choose","instructions":"Read and answer details.","exercises":[{"sentence":"Last winter, I spent a week in the Swiss Alps. The snow was incredibly deep.","question":"Where did the person go?","options":["The beach","The mountains","The city"],"correct":1,"explanation":"Swiss Alps are mountains."},{"sentence":"I stayed in a small wooden cabin with a warm fireplace.","question":"What kind of house was it?","options":["Brick","Wooden","Stone"],"correct":1,"explanation":"Wooden cabin."},{"sentence":"Every morning, I went skiing for four hours before lunch.","question":"How long did they ski?","options":["2 hours","4 hours","all day"],"correct":1,"explanation":"Skiing for four hours."},{"sentence":"In the evenings, I drank hot chocolate and read books.","question":"What did they do in the evening?","options":["Dance","Read","Cook"],"correct":1,"explanation":"Read books."},{"sentence":"I met many interesting people from different countries there.","question":"Who did they meet?","options":["Only locals","Diverse travelers","Family"],"correct":1,"explanation":"People from different countries."}]}', 11),
('en', 'A2', 'reading', 'Job Application Email', 'Formal communication.', '{"type":"read_and_choose","instructions":"Understand the job inquiry.","exercises":[{"sentence":"Dear Manager, I am writing to apply for the position of Sales Assistant.","question":"What job is the person applying for?","options":["Chef","Sales Assistant","Driver"],"correct":1,"explanation":"Sales Assistant."},{"sentence":"I have three years of experience in retail and customer service.","question":"How much experience do they have?","options":["1 year","2 years","3 years"],"correct":2,"explanation":"Three years."},{"sentence":"I am available to work weekends and evening shifts.","question":"When can they work?","options":["Only mornings","Evenings/Weekends","Mondays only"],"correct":1,"explanation":"Available weekends and evening shifts."},{"sentence":"Please find my resume attached to this email.","question":"What else is in the email?","options":["A photo","A resume","A letter"],"correct":1,"explanation":"Resume attached."},{"sentence":"I look forward to hearing from you. Sincerely, Jane Doe.","question":"Who is Jane Doe?","options":["The manager","The applicant"],"correct":1,"explanation":"Jane is the one writing."}]}', 12),
('en', 'A2', 'reading', 'Healthy Living Tips', 'Short advice snippets.', '{"type":"read_and_choose","instructions":"Find the health advice.","exercises":[{"sentence":"Drinking eight glasses of water every day keeps you hydrated.","question":"How much water is recommended?","options":["4 glasses","8 glasses","12 glasses"],"correct":1,"explanation":"Eight glasses."},{"sentence":"Walking for thirty minutes can improve your mood and energy.","question":"How long should you walk?","options":["10 mins","30 mins","1 hour"],"correct":1,"explanation":"Thirty minutes."},{"sentence":"Eating more greens, like spinach and broccoli, is good for you.","question":"Which veg is mentioned?","options":["Carrots","Broccoli","Corn"],"correct":1,"explanation":"Spinach and broccoli."},{"sentence":"Try to sleep at least seven hours for a better brain.","question":"Minimum sleep?","options":["5 hours","7 hours","9 hours"],"correct":1,"explanation":"At least seven hours."},{"sentence":"Reducing sugar helps to prevent many health problems.","question":"What should be reduced?","options":["Water","Sugar","Salt"],"correct":1,"explanation":"Reducing sugar."}]}', 13),
('en', 'A2', 'reading', 'A Day in London', 'City tour itinerary.', '{"type":"read_and_choose","instructions":"Sequence of the day.","exercises":[{"sentence":"We started the day by visiting the British Museum at 10am.","question":"Arrival time?","options":["9am","10am","11bit"],"correct":1,"explanation":"10am."},{"sentence":"Later, we walked across the bridge to see Big Ben.","question":"What did they see next?","options":["A park","Big Ben","The palace"],"correct":1,"explanation":"To see Big Ben."},{"sentence":"For lunch, we found a traditional pub and had fish and chips.","question":"What was the lunch?","options":["Pasta","Pizza","Fish and chips"],"correct":2,"explanation":"Fish and chips."},{"sentence":"In the afternoon, we took a boat trip on the River Thames.","question":"How did they travel in the afternoon?","options":["By bus","By boat","By foot"],"correct":1,"explanation":"Took a boat trip."},{"sentence":"We finished the day watching a musical in the West End.","question":"Where was the final activity?","options":["East End","West End","North London"],"correct":1,"explanation":"West End."}]}', 14),
('en', 'A2', 'reading', 'Environment Report', 'Simple environmental facts.', '{"type":"read_and_choose","instructions":"Find the environment info.","exercises":[{"sentence":"Recycling paper and plastic helps to save our forests and oceans.","question":"What helps save forests?","options":["Paper recycling","Driving","Cooking"],"correct":0,"explanation":"Recycling paper."},{"sentence":"Using less electricity can lower your monthly bills and carbon footprint.","question":"Benefit of less electricity?","options":["More noise","Lower bills","Higher taxes"],"correct":1,"explanation":"Lower bills."},{"sentence":"Planting trees provides more oxygen and homes for birds.","question":"What do trees provide?","options":["Only heat","Oxygen/Homes","Food"],"correct":1,"explanation":"Oxygen and homes."},{"sentence":"Biking to work is a great way to stay fit and help the planet.","question":"Why bike?","options":["It''s slow","Stay fit/Help planet","Cheap cars"],"correct":1,"explanation":"Stay fit and help planet."},{"sentence":"Avoid using plastic bags and bring your own cloth bag.","question":"What is the recommendation?","options":["Use more plastic","Use cloth bags"],"correct":1,"explanation":"Bring your own cloth bag."}]}', 15);
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'A2', 'writing', 'Connectors: And, But, So', 'Combine sentences correctly.', '{"type":"type_word","instructions":"Type the correct connector.","exercises":[{"prompt":"I was hungry, [and/but] I ate a sandwich.","expected":"so","hint":"Result of being hungry."},{"prompt":"He likes coffee, [and/but] she likes tea.","expected":"but","hint":"Showing contrast."},{"prompt":"I bought milk [and/but] bread.","expected":"and","hint":"Adding items."},{"prompt":"It was raining, [so/but] we didn''t go out.","expected":"so","hint":"Consequence."},{"prompt":"The movie was long [and/but] interesting.","expected":"but","hint":"Opposite qualities."}]}', 11),
('en', 'A2', 'writing', 'Present Continuous', 'Describe what is happening now.', '{"type":"type_word","instructions":"Type the -ing form.","exercises":[{"prompt":"I am [read] a book.","expected":"reading","hint":"Ongoing action."},{"prompt":"They are [play] football.","expected":"playing","hint":"Group action."},{"prompt":"She is [dance] in the room.","expected":"dancing","hint":"Movement."},{"prompt":"We are [wait] for the bus.","expected":"waiting","hint":"Expectation."},{"prompt":"He is [cook] dinner.","expected":"cooking","hint":"Kitchen action."}]}', 12),
('en', 'A2', 'writing', 'Simple Past Tense', 'Change verbs to past tense.', '{"type":"type_word","instructions":"Type the past form.","exercises":[{"prompt":"Yesterday I [walk] to work.","expected":"walked","hint":"Regular past."},{"prompt":"I [buy] a new phone.","expected":"bought","hint":"Irregular past."},{"prompt":"She [see] a cat.","expected":"saw","hint":"Irregular sight."},{"prompt":"We [eat] pizza.","expected":"ate","hint":"Irregular food verb."},{"prompt":"They [play] games.","expected":"played","hint":"Regular past."}]}', 13),
('en', 'A2', 'writing', 'Comparison Time', 'Use comparatives correctly.', '{"type":"type_word","instructions":"Type the comparative form.","exercises":[{"prompt":"London is [big] than Oxford.","expected":"bigger","hint":"Double the ''g''."},{"prompt":"The sun is [hot] than the moon.","expected":"hotter","hint":"Double the ''t''."},{"prompt":"This book is [good] than that one.","expected":"better","hint":"Irregular form."},{"prompt":"I am [tall] than my brother.","expected":"taller","hint":"Standard -er."},{"prompt":"Traveling by train is [fast] than by car.","expected":"faster","hint":"Standard -er."}]}', 14),
('en', 'A2', 'writing', 'Quantifiers', 'Few, many, much, some.', '{"type":"type_word","instructions":"Type the quantifier.","exercises":[{"prompt":"There is [many/much] water in the glass.","expected":"much","hint":"Uncountable noun."},{"prompt":"I have [many/much] friends.","expected":"many","hint":"Countable noun."},{"prompt":"She needs [some] help.","expected":"some","hint":"Positive request."},{"prompt":"There are a [few] apples left.","expected":"few","hint":"Small countable number."},{"prompt":"Do you have [any] sugar?","expected":"any","hint":"Question form."}]}', 15);
